#include <stdio.h>
#include <stdint.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        uint32_t x;
        scanf("%u", &x);
        // GCC/Clang built‑in popcount for 32‑bit values
        int cnt = __builtin_popcount(x);
        printf("%d\n", cnt);
    }
    return 0;
}

