import sys

def main():
    data = sys.stdin.read().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t+1):
        x = int(data[i])
        out.append(str(bin(x).count('1')))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

