const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let result = [];
for (let i = 0; i < T; i++) {
  const x = Number(input[idx++]);
  // JavaScript numbers are safe up to 2^53, so 32‑bit values are fine.
  let cnt = 0;
  let v = x >>> 0; // ensure unsigned 32‑bit
  while (v) {
    v &= v - 1;
    cnt++;
  }
  result.push(cnt.toString());
}
console.log(result.join('\n'));

